def _calculate_semantic_depth(text: str) -> float:
    # Heuristic complexity scoring
    word_count = len(text.split())
    unique_words = len(set(text.split()))
    complexity_factors = [
        len(re.findall(r'\b\w+ly\b', text)) * 0.5,  # Adverb complexity
        len(re.findall(r'\b[A-Z]\w+', text)) * 0.3,  # Proper noun depth
        len(re.findall(r'\b\w+ed\b', text)) * 0.2   # Past tense complexity
    ]
    
    depth_score = min(
        (word_count * 0.3) + 
        (unique_words * 0.5) + 
        sum(complexity_factors),
        10.0  # Cap at 10
    )
    
    return round(depth_score, 2)

